const event = $input.first().json.events?.[0] || $input.first().json.body?.events?.[0];
const messageText = event?.message?.text || '';
const replyToken = event?.replyToken || '';
const userId = event?.source?.userId || '';

// 格式：生成文案 YC123456 風格描述（YC 前空白可省略）
const m = messageText.match(/^生成文案[\s]*([Yy][Cc]\w+)[\s\u3000]+(.+)$/);
if (!m) {
  throw new Error(`指令格式錯誤。應為：生成文案 YC編號 風格描述\n收到：「${messageText}」`);
}
const caseId = m[1].toUpperCase();
const styleText = m[2].trim();

return [{ json: { caseId, styleText, replyToken, userId, rawMessage: messageText } }];

const cmd = $('解析 LINE 指令').first().json;
const page = ($json.results || [])[0];
if (!page) {
  throw new Error(`找不到 ${cmd.caseId}，請確認案件編號是否存在於 Notion`);
}

const props = page.properties || {};
const rt = k => (props[k]?.rich_text?.[0]?.plain_text) || '';
const tt = k => (props[k]?.title?.[0]?.plain_text) || '';
const sel = k => props[k]?.select?.name || '';
const num = k => props[k]?.number ?? null;
const chk = k => !!props[k]?.checkbox;

const data = {
  notionPageId: page.id,
  existingVersion: num('文案版本') || 0,
  案名: tt('案名'),
  案件編號: rt('案件編號'),
  社區名稱: rt('社區名稱'),
  地址: rt('地址'),
  建物類型: sel('建物類型'),
  格局: rt('格局'),
  樓層: rt('樓層'),
  屋齡: num('屋齡'),
  總價: rt('總價'),
  單價: rt('單價'),
  建物坪數: num('建物坪數'),
  主建物坪數: num('主建物坪數'),
  公設坪數: num('公設坪數'),
  附屬建物: rt('附屬建物'),
  土地坪數: num('土地坪數'),
  有無車位: chk('有無車位'),
  車位類型: sel('車位類型'),
  特色說明: rt('特色說明'),
  舊文案: rt('產生的文案'),
  styleText: cmd.styleText,
  replyToken: cmd.replyToken,
  caseId: cmd.caseId
};
return [{ json: data }];

