const response = $input.first().json;
const aiText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
let jsonText = aiText.trim().replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
let parsed;
try { parsed = JSON.parse(jsonText); }
catch (e) {
  // 若 AI 沒回 JSON，直接把整段當文案吃進去
  parsed = { 產生的文案: aiText.trim() };
}
const src = $('取出物件資料').first().json;
return [{ json: { ...src, 新文案: parsed['產生的文案'] || aiText.trim(), newVersion: (src.existingVersion || 0) + 1 } }];

const notionPage = $input.first().json;
const src = $('解析 AI 輸出').first().json;
const notionUrl = notionPage.url || `https://www.notion.so/${String(notionPage.id || '').replace(/-/g, '')}`;
const replyText = `✅ 文案已重產（v${src.newVersion}）

📋 ${src['案名']}
🏷 ${src.caseId}
🎨 風格：${src.styleText}
🔗 ${notionUrl}

━━━ 新文案 ━━━
${src['新文案']}`;
return [{ json: { replyToken: src.replyToken, replyText } }];
